// D-Score Match calculation (same as Python dscore_formula_v2)
function norm(val,lo,hi,inv=false){
  if(hi===lo)return 0.5;
  let n=Math.max(0,Math.min(1,(val-lo)/(hi-lo)));
  return inv?1-n:n;
}

function dScoreMatch(player, opp, isHome) {
  const p = player;
  const aa5 = p.aa5;
  
  // Socle joueur (50%)
  const form = norm(p.l5, 25, 80);
  const l10bonus = p.l10 > p.l5 ? norm(p.l10, 30, 80) * 5 : 0; // L10 > L5 = qualité longue durée
  const aa = norm(aa5, -5, 35);
  const flN = norm(p.fl, 15, 70);
  const reg = norm(p.reg, 0, 100);
  const gaBonus = norm(p.ga||0, 0, 0.8) * 6; // G+A/match, max 0.8 = 6pts
  const socle = form*13 + l10bonus + aa*12 + flN*7 + reg*7 + gaBonus;
  
  // Contexte match (45%)
  const oppPpda = isHome ? opp.ppe : opp.ppd;
  const oppXga = isHome ? opp.xgae : opp.xgad;
  const oppXg = isHome ? (opp.xgae||opp.xga) : (opp.xgad||opp.xga);
  
  let ctx = 0;
  const pos = p.p;
  
  if (pos === "GK") {
    ctx = norm(oppXg,0.7,2.5,true)*22 + norm(oppPpda,7,20)*16 + norm(p.l5,20,70)*12;
  } else if (pos === "DEF") {
    const cAtt = norm(oppXg,0.7,2.5,true);
    const cStyle = aa5>18 ? norm(oppPpda,7,20,true) : norm(oppPpda,7,20);
    ctx = cAtt*20 + cStyle*16 + norm(p.l5,20,75)*14;
  } else if (pos === "MIL") {
    if (aa5 >= 10) { // Relanceur/B2B/GOAT
      ctx = norm(oppPpda,7,20)*26 + norm(oppXga,0.8,2.0)*8 + norm(p.l5,25,75)*16;
    } else { // Créateur/Dribbleur (AA<10)
      ctx = norm(oppXga,0.8,2.0)*22 + norm(oppPpda,7,20,true)*14 + norm(p.l5,20,80)*14;
    }
  } else if (pos === "ATT") {
    if (aa5 >= 8) { // ATT Complet
      ctx = norm(oppXga,0.8,2.0)*26 + norm(oppPpda,7,20,true)*9 + norm(p.l5,20,80)*15;
    } else {
      ctx = norm(oppXga,0.8,2.0)*25 + norm(oppPpda,7,20,true)*14 + norm(p.l5,20,80)*11;
    }
  }
  
  // Momentum (15%) — basé sur le L2 (forme récente)
  const sc = p.sc || [];
  const l2 = sc.length >= 2 ? (sc[0]+sc[1])/2 : sc.length === 1 ? sc[0] : p.l5;
  const trend = p.l5 > 0 ? (l2 - p.l5) / p.l5 * 100 : 0; // % hausse/baisse vs L5
  // trend > 0 = le joueur est bouillant, en confiance
  // trend < 0 = le joueur est en baisse
  const trendScore = norm(trend, -30, 40) * 10; // -30% = 0pts, +40% = 10pts
  const hotStreak = sc.length >= 2 && sc[0] >= 65 && sc[1] >= 65 ? 3 : 0; // bonus si 2 derniers matchs > 65
  const coldStreak = sc.length >= 2 && sc[0] < 40 && sc[1] < 40 ? -3 : 0; // malus si 2 derniers < 40
  const momentum = trendScore + hotStreak + coldStreak + 2; // +2 base
  
  // Bonus DOM/EXT joueur (+3 dom, -2 ext)
  const domBonus = isHome ? 5 : -3;
  
  // Raw
  let d = socle + ctx + momentum + domBonus;
  
  // Garde-fous
  const floorMin = p.fl / 100 * 55;
  // Team boost simplified: top clubs get 1.10
  let boost = 1.0;
  d = Math.max(floorMin, Math.min(95, d * boost));
  
  return Math.round(d);
}

