function Badge({score,size=48}){
  const bg=score>=75?"linear-gradient(135deg,#F59E0B,#D97706)":score>=65?"linear-gradient(135deg,#22C55E,#15803D)":score>=55?"linear-gradient(135deg,#06B6D4,#0E7490)":score>=45?"linear-gradient(135deg,#F97316,#C2410C)":score>=35?"linear-gradient(135deg,#EF4444,#B91C1C)":"linear-gradient(135deg,#6B7280,#4B5563)";
  const gw=score>=75?"rgba(245,158,11,0.5)":score>=65?"rgba(34,197,94,0.4)":score>=55?"rgba(6,182,212,0.3)":score>=45?"rgba(249,115,22,0.3)":score>=35?"rgba(239,68,68,0.3)":"rgba(107,114,128,0.2)";
  return <div style={{width:size,height:size,borderRadius:"50%",background:bg,boxShadow:`0 2px 10px rgba(0,0,0,0.5),0 0 16px ${gw}`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:size*.38,fontWeight:800,color:"#fff",border:"2px solid rgba(255,255,255,0.3)",fontFamily:"'Space Mono',monospace",margin:"0 auto"}}>{score}</div>;
}

function Bars({scores}){
  const h=22,gc=s=>s>=70?"#22C55E":s>=55?"#84CC16":s>=40?"#EAB308":"#EF4444";
  return <div style={{display:"flex",alignItems:"flex-end",gap:2,justifyContent:"center",height:h}}>
    {(scores||[]).slice(0,5).map((s,i)=><div key={i} style={{width:6,borderRadius:"2px 2px 0 0",height:`${Math.max(s/100*h,3)}px`,background:gc(s),opacity:i===0?1:0.4+i*0.12}}/>)}
  </div>;
}


function DStars({score}){
  const n=score>=75?5:score>=60?4:score>=50?3:score>=40?2:score>=30?1:0;
  const isFull=n===5;
  return <div style={{display:"flex",gap:2,justifyContent:"center",marginTop:4,position:"relative"}}>
    {isFull&&<div style={{position:"absolute",inset:"-4px -6px",borderRadius:8,background:"radial-gradient(ellipse,rgba(251,191,36,0.2) 0%,transparent 70%)",animation:"starGlow 1.5s ease-in-out infinite",pointerEvents:"none"}}/>}
    {Array.from({length:5},(_,i)=>(
      <svg key={i} width="14" height="14" viewBox="0 0 24 24" style={{
        filter:i<n&&isFull?"drop-shadow(0 0 4px rgba(251,191,36,0.8))":"none",
        animation:i<n&&isFull?`starPulse 1.2s ease-in-out infinite ${i*0.15}s`:"none",
      }}>
        <path d="M12 2l3.09 6.26L22 9.27l-5 4.87 1.18 6.88L12 17.77l-6.18 3.25L7 14.14 2 9.27l6.91-1.01L12 2z"
          fill={i<n?"#FBBF24":"rgba(255,255,255,0.08)"} stroke={i<n?"#F59E0B":"none"} strokeWidth="0.5"/>
      </svg>
    ))}
  </div>;
}

function Stat({label,v1,v2}){
  const w1=v1>v2,w2=v2>v1;
  const isD=label==="D-Score";
  return <div style={{padding:"5px 0",borderBottom:"1px solid rgba(255,255,255,0.03)"}}>
    <div style={{display:"grid",gridTemplateColumns:"1fr auto 1fr",gap:4,alignItems:"center"}}>
      <div style={{textAlign:"right",fontSize:isD?18:14,fontWeight:800,fontFamily:"'Space Mono',monospace",color:w1?"#4ADE80":"rgba(255,255,255,0.4)"}}>{v1}</div>
      <div style={{fontSize:isD?10:9,color:isD?"#FBBF24":"rgba(255,255,255,0.35)",fontWeight:700,textAlign:"center",width:55,letterSpacing:"0.05em"}}>{label}</div>
      <div style={{textAlign:"left",fontSize:isD?18:14,fontWeight:800,fontFamily:"'Space Mono',monospace",color:w2?"#4ADE80":"rgba(255,255,255,0.4)"}}>{v2}</div>
    </div>
    <div style={{textAlign:"center",fontSize:10,color:"rgba(255,255,255,0.30)",marginTop:2,fontStyle:"italic"}}>{STAT_DESC[label]||""}</div>
  </div>;
}

function Sel({value,onChange,options,placeholder}){
  return <select value={value} onChange={e=>onChange(e.target.value)} style={{
    background:"rgba(255,255,255,0.06)",color:"#fff",border:"1px solid rgba(255,255,255,0.1)",
    borderRadius:8,padding:"10px 12px",fontSize:12,fontWeight:600,width:"100%",appearance:"none",cursor:"pointer",outline:"none",
  }}><option value="" style={{background:"#111"}}>{placeholder}</option>
    {options.map(o=><option key={o} value={o} style={{background:"#111"}}>{o}</option>)}
  </select>;
}

function genVerdict(p,opp,isHome,d){
  if(!p||!opp)return"";
  const ppda=isHome?opp.ppe:opp.ppd;
  const xga=isHome?opp.xgae:opp.xgad;
  const xg=isHome?(opp.xgae||opp.xga):(opp.xgad||opp.xga);
  const lieu=isHome?"à domicile":"en déplacement";
  const lieuAdv=isHome?"en extérieur":"à domicile";
  const styleLabel=ppda>13?"bloc bas":ppda>10?"jeu équilibré":"pressing haut";
  const sc=p.sc||[];
  const l2=sc.length>=2?(sc[0]+sc[1])/2:p.l5;
  const trend=p.l5>0?((l2-p.l5)/p.l5*100):0;
  
  let t="";
  
  // 1. Forme du joueur + alertes
  if(sc.length>0&&sc[0]===0)t+="⛔ "+p.n+" n'a PAS JOUÉ son dernier match (score 0) — suspendu ou blessé ? Vérifie avant de le pick ! ";
  else if(sc.length>1&&sc[0]<20&&sc[1]<20)t+="🚨 "+p.n+" a scoré très bas sur ses 2 derniers matchs ("+sc[0]+", "+sc[1]+") — possible remplaçant ou méforme. ";
  else if(trend>15)t+=p.n+" est en feu 🔥 (L2="+Math.round(l2)+" vs L5="+p.l5+", +"+Math.round(trend)+"%). ";
  else if(trend>5)t+=p.n+" est en bonne forme (L2="+Math.round(l2)+", tendance +"+Math.round(trend)+"%). ";
  else if(trend<-15)t+=p.n+" est en baisse ⚠️ (L2="+Math.round(l2)+" vs L5="+p.l5+", "+Math.round(trend)+"%). ";
  else t+=p.n+" est régulier (L5="+p.l5+"). ";
  if(p.ga>=0.5)t+="Meilleur ratio G+A de sa ligue ("+p.ga+"/match). ";
  
  // 2. Contexte DOM/EXT
  if(isHome)t+="Il joue à domicile (+) contre "+opp.name+". ";
  else t+="Il se déplace chez "+opp.name+" (-). ";
  
  // 3. Analyse adversaire selon le poste
  if(p.p==="GK"||p.p==="DEF"){
    t+=opp.name+" "+lieuAdv+" joue en "+styleLabel+" (PPDA "+ppda+"). ";
    if(xg<1.0)t+="Leur attaque est quasi inexistante ("+xg+" xG/match) → CS très probable ! ";
    else if(xg<1.3)t+="Faible attaque adverse ("+xg+" xG) → CS probable. ";
    else if(xg>1.8)t+="⚠️ Attaque dangereuse ("+xg+" xG/match) → risque de but encaissé. ";
    else t+="Attaque correcte ("+xg+" xG). ";
    if(ppda>13)t+="Le bloc bas = peu de tirs cadrés → favorable pour le CS. ";
    else if(ppda<10)t+="Pressing haut = match ouvert → plus de travail défensif (tacles, interceptions). ";
    if(p.p==="DEF"&&p.aa5>=18)t+="Son AA5 de "+p.aa5+" est exceptionnel → il va monter et créer. ";
  }
  
  if(p.p==="MIL"){
    t+=opp.name+" "+lieuAdv+" joue en "+styleLabel+" (PPDA "+ppda+"). ";
    if(p.aa5>=10){
      if(ppda>13)t+="Bloc bas = "+p.n+" va monopoliser le ballon, accumuler passes et possession → AA garanti. ";
      else if(ppda>10)t+="Jeu équilibré → du travail des deux côtés du terrain. ";
      else t+="Pressing haut = match ouvert → récupérations hautes et transitions rapides. ";
    }else{
      if(xga>1.6)t+=opp.name+" encaisse "+xga+" xGA "+lieuAdv+" → passoire ! Espaces pour créer. ";
      else if(xga<1.2)t+="Défense solide adverse ("+xga+" xGA) → peu d'espaces pour créer. ";
      if(ppda<10)t+="Pressing haut adverse → espaces dans le dos pour "+p.n+". ";
    }
    if(p.dsr>=50)t+="DSR "+p.dsr+"% = il contribue souvent aux buts. ";
  }
  
  if(p.p==="ATT"){
    t+=opp.name+" "+lieuAdv+" encaisse "+xga+" xGA/match";
    if(xga>1.8)t+=" → véritable passoire ! "+p.n+" va avoir plein d'occasions. ";
    else if(xga>1.5)t+=" → défense fragile, des occasions à saisir. ";
    else if(xga<1.1)t+=" → défense très solide. Ce sera dur pour "+p.n+". ";
    else t+=". ";
    t+=opp.name+" joue en "+styleLabel+" (PPDA "+ppda+"). ";
    if(ppda>13)t+="⚠️ Bloc bas = adversaire regroupé, moins d'espaces pour un attaquant. ";
    else if(ppda<10)t+="Pressing haut = des espaces dans le dos de la défense ! ";
    if(p.dsr>=70)t+="Avec "+p.dsr+"% de matchs décisifs, "+p.n+" devrait scorer. ";
    else if(p.dsr>=40)t+="DSR "+p.dsr+"% → une action décisive est probable. ";
    else if(p.dsr<20)t+="DSR faible ("+p.dsr+"%) → dépend surtout de son AA. ";
  }
  
  // 4. Floor / conclusion
  if(p.fl>=55)t+="Floor "+p.fl+" = sécurité maximale, tu ne prends aucun risque.";
  else if(p.fl>=45)t+="Floor "+p.fl+" = filet correct, pick fiable.";
  else if(p.fl>=35)t+="Floor "+p.fl+" = attention, si soirée sans, le score peut chuter.";
  else t+="Floor "+p.fl+" = risqué, tout repose sur une action décisive.";
  
  return t;
}



function playBellSound() {
  try {
    const ctx = new (window.AudioContext || window.webkitAudioContext)();
    // Bell hit
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();
    osc.connect(gain);
    gain.connect(ctx.destination);
    osc.type = "sine";
    osc.frequency.setValueAtTime(800, ctx.currentTime);
    osc.frequency.exponentialRampToValueAtTime(400, ctx.currentTime + 0.3);
    gain.gain.setValueAtTime(0.6, ctx.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.01, ctx.currentTime + 0.8);
    osc.start(ctx.currentTime);
    osc.stop(ctx.currentTime + 0.8);
    // Second harmonic for metallic feel
    const osc2 = ctx.createOscillator();
    const gain2 = ctx.createGain();
    osc2.connect(gain2);
    gain2.connect(ctx.destination);
    osc2.type = "sine";
    osc2.frequency.setValueAtTime(1200, ctx.currentTime);
    osc2.frequency.exponentialRampToValueAtTime(600, ctx.currentTime + 0.2);
    gain2.gain.setValueAtTime(0.3, ctx.currentTime);
    gain2.gain.exponentialRampToValueAtTime(0.01, ctx.currentTime + 0.5);
    osc2.start(ctx.currentTime);
    osc2.stop(ctx.currentTime + 0.5);
    // Third ring
    const osc3 = ctx.createOscillator();
    const gain3 = ctx.createGain();
    osc3.connect(gain3);
    gain3.connect(ctx.destination);
    osc3.type = "triangle";
    osc3.frequency.setValueAtTime(2000, ctx.currentTime);
    osc3.frequency.exponentialRampToValueAtTime(800, ctx.currentTime + 0.15);
    gain3.gain.setValueAtTime(0.15, ctx.currentTime);
    gain3.gain.exponentialRampToValueAtTime(0.01, ctx.currentTime + 0.3);
    osc3.start(ctx.currentTime);
    osc3.stop(ctx.currentTime + 0.3);
  } catch(e) {}
}

function playPunchSound() {
  try {
    const ctx = new (window.AudioContext || window.webkitAudioContext)();
    // Low thump
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();
    osc.connect(gain);
    gain.connect(ctx.destination);
    osc.type = "sine";
    osc.frequency.setValueAtTime(150, ctx.currentTime);
    osc.frequency.exponentialRampToValueAtTime(50, ctx.currentTime + 0.15);
    gain.gain.setValueAtTime(0.8, ctx.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.01, ctx.currentTime + 0.2);
    osc.start(ctx.currentTime);
    osc.stop(ctx.currentTime + 0.2);
    // Noise burst for impact
    const bufferSize = ctx.sampleRate * 0.1;
    const buffer = ctx.createBuffer(1, bufferSize, ctx.sampleRate);
    const data = buffer.getChannelData(0);
    for (let i = 0; i < bufferSize; i++) data[i] = (Math.random() * 2 - 1) * Math.pow(1 - i/bufferSize, 3);
    const noise = ctx.createBufferSource();
    noise.buffer = buffer;
    const noiseGain = ctx.createGain();
    noise.connect(noiseGain);
    noiseGain.connect(ctx.destination);
    noiseGain.gain.setValueAtTime(0.4, ctx.currentTime);
    noise.start(ctx.currentTime);
  } catch(e) {}
}

function playKOSound() {
  try {
    const ctx = new (window.AudioContext || window.webkitAudioContext)();
    // Crowd roar = filtered noise
    const bufferSize = ctx.sampleRate * 0.8;
    const buffer = ctx.createBuffer(1, bufferSize, ctx.sampleRate);
    const data = buffer.getChannelData(0);
    for (let i = 0; i < bufferSize; i++) data[i] = (Math.random() * 2 - 1) * Math.min(1, i/5000) * Math.pow(1 - i/bufferSize, 0.5);
    const noise = ctx.createBufferSource();
    noise.buffer = buffer;
    const filter = ctx.createBiquadFilter();
    filter.type = "bandpass";
    filter.frequency.value = 600;
    filter.Q.value = 0.5;
    const gain = ctx.createGain();
    noise.connect(filter);
    filter.connect(gain);
    gain.connect(ctx.destination);
    gain.gain.setValueAtTime(0.3, ctx.currentTime);
    noise.start(ctx.currentTime);
  } catch(e) {}
}


